"use client";

import Link from "next/link";
import { usePathname } from "next/navigation";
import { Home, Bike, Wallet, User, ShoppingBag } from "lucide-react";

export default function BottomNav() {
  const pathname = usePathname();

  const navItems = [
    { label: "Home", icon: Home, href: "/" },
    { label: "Catalog", icon: Bike, href: "/catalog" },
    { label: "Cart", icon: ShoppingBag, href: "/checkout" },
    { label: "Admin", icon: User, href: "/admin" },
  ];

  return (
    <nav className="fixed bottom-0 left-0 right-0 z-50 flex h-20 items-center justify-around border-t border-slate-200 bg-white/95 backdrop-blur-md px-4 pb-4">
      {navItems.map((item) => {
        const isActive = pathname === item.href;
        return (
          <Link
            key={item.label}
            href={item.href}
            className={`flex flex-col items-center gap-1 transition-colors ${
              isActive ? "text-primary" : "text-slate-400"
            }`}
          >
            <item.icon size={24} strokeWidth={isActive ? 2.5 : 2} />
            <span className="text-[10px] font-bold uppercase tracking-wider">
              {item.label}
            </span>
          </Link>
        );
      })}
    </nav>
  );
}
